<?php
if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Admin { const OPTION_GROUP = 'tct_settings_group'; const OPTION_NAME_CLIENT_ID = 'tct_todoist_client_id'; const OPTION_NAME_CLIENT_SECRET = 'tct_todoist_client_secret'; const OPTION_NAME_SYNC_INTERVAL = 'tct_sync_interval_minutes'; const OPTION_NAME_SYNC_HORIZON = 'tct_sync_horizon_days'; const OPTION_NAME_PROGRESS_IMAGES_ENABLED = 'tct_progress_images_enabled'; const OPTION_NAME_TIMEZONE = 'tct_timezone'; const OPTION_NAME_EXPERIMENTAL_FEATURES_ENABLED = 'tct_experimental_features_enabled'; const OPTION_NAME_END_OF_DAY_TIME = 'tct_end_of_day_time'; const OPTION_NAME_SETTINGS_SCHEMA_VERSION = 'tct_settings_schema_version'; const SETTINGS_SCHEMA_VERSION = 1; public function __construct() { add_action( 'admin_menu', array( $this, 'admin_menu' ) ); add_action( 'admin_init', array( __CLASS__, 'maybe_upgrade_settings_schema' ), 1 ); add_action( 'admin_init', array( $this, 'register_settings' ) ); } public static function get_client_id() { return (string) get_option( self::OPTION_NAME_CLIENT_ID, '' ); } public static function get_client_secret() { return (string) get_option( self::OPTION_NAME_CLIENT_SECRET, '' ); } public static function get_sync_interval_minutes() { $v = (int) get_option( self::OPTION_NAME_SYNC_INTERVAL, 15 ); if ( ! in_array( $v, array( 5, 15, 30 ), true ) ) { $v = 15; } return $v; } public static function get_sync_horizon_days() { $v = (int) get_option( self::OPTION_NAME_SYNC_HORIZON, 120 ); if ( $v < 1 ) { $v = 120; } if ( $v > 365 ) { $v = 365; } return $v; } public static function get_timezone() { $val = trim( (string) get_option( self::OPTION_NAME_TIMEZONE, '' ) ); if ( '' === $val ) { return ''; } try { new DateTimeZone( $val ); } catch ( Exception $e ) { return ''; } return $val; } public static function get_end_of_day_time() { $val = trim( (string) get_option( self::OPTION_NAME_END_OF_DAY_TIME, '' ) ); if ( '' === $val ) { return ''; } if ( 1 !== preg_match( '/^\d{2}:\d{2}$/', $val ) ) { return ''; } $parts = explode( ':', $val, 2 ); if ( 2 !== count( $parts ) ) { return ''; } $h = (int) $parts[0]; $m = (int) $parts[1]; if ( $h < 0 || $h > 23 || $m < 0 || $m > 59 ) { return ''; } return sprintf( '%02d:%02d', $h, $m ); } public static function is_progress_images_enabled() { if ( defined( 'TCT_FEATURE_REWARD_PROGRESS_IMAGES' ) ) { return (bool) TCT_FEATURE_REWARD_PROGRESS_IMAGES; } return (bool) get_option( self::OPTION_NAME_PROGRESS_IMAGES_ENABLED, false ); } public static function is_experimental_features_enabled() { if ( defined( 'TCT_FEATURE_EXPERIMENTAL' ) ) { return (bool) TCT_FEATURE_EXPERIMENTAL; } return (bool) get_option( self::OPTION_NAME_EXPERIMENTAL_FEATURES_ENABLED, false ); } public static function maybe_upgrade_settings_schema( $return_details = false ) { $details = array( 'didRun' => false, 'fromVersion' => (int) get_option( self::OPTION_NAME_SETTINGS_SCHEMA_VERSION, 0 ), 'toVersion' => (int) get_option( self::OPTION_NAME_SETTINGS_SCHEMA_VERSION, 0 ), 'targetVersion' => (int) self::SETTINGS_SCHEMA_VERSION, 'backupFilename'=> '', 'backupError' => '', ); if ( ! is_admin() ) { return $return_details ? $details : null; } if ( ! current_user_can( 'manage_options' ) ) { return $return_details ? $details : null; } $installed = (int) $details['fromVersion']; if ( $installed >= self::SETTINGS_SCHEMA_VERSION ) { return $return_details ? $details : null; } $details['didRun'] = true; if ( class_exists( 'TCT_Backup' ) && is_callable( array( 'TCT_Backup', 'create_backup' ) ) ) { $err = ''; $fn = TCT_Backup::create_backup( 'migration', $err ); if ( $fn ) { $details['backupFilename'] = $fn; } if ( '' !== $err ) { $details['backupError'] = $err; } if ( class_exists( 'TCT_Utils' ) && is_callable( array( 'TCT_Utils', 'debug_log' ) ) ) { if ( $fn ) { TCT_Utils::debug_log( 'settings_schema_backup_created', array( 'file' => $fn, 'type' => 'migration' ) ); } elseif ( '' !== $err ) { TCT_Utils::debug_log( 'settings_schema_backup_failed', array( 'error' => $err ), 'error' ); } } } if ( class_exists( 'TCT_Utils' ) && is_callable( array( 'TCT_Utils', 'debug_log' ) ) ) { TCT_Utils::debug_log( 'settings_schema_migration_start', array( 'from' => $installed, 'to' => self::SETTINGS_SCHEMA_VERSION, ) ); } while ( $installed < self::SETTINGS_SCHEMA_VERSION ) { $next = $installed + 1; switch ( $next ) { case 1: self::migrate_settings_to_v1(); break; default: if ( class_exists( 'TCT_Utils' ) && is_callable( array( 'TCT_Utils', 'debug_log' ) ) ) { TCT_Utils::debug_log( 'settings_schema_migration_unknown_target', array( 'target' => $next ), 'error' ); } $details['toVersion'] = (int) get_option( self::OPTION_NAME_SETTINGS_SCHEMA_VERSION, 0 ); return $return_details ? $details : null; } $installed = $next; update_option( self::OPTION_NAME_SETTINGS_SCHEMA_VERSION, $installed ); } $details['toVersion'] = (int) $installed; if ( class_exists( 'TCT_Utils' ) && is_callable( array( 'TCT_Utils', 'debug_log' ) ) ) { TCT_Utils::debug_log( 'settings_schema_migration_complete', array( 'version' => $installed ) ); } return $return_details ? $details : null; } private static function migrate_settings_to_v1() { $interval_raw = get_option( self::OPTION_NAME_SYNC_INTERVAL, 15 ); $interval = (int) $interval_raw; if ( ! in_array( $interval, array( 5, 15, 30 ), true ) ) { $interval = 15; } if ( (string) $interval_raw !== (string) $interval ) { update_option( self::OPTION_NAME_SYNC_INTERVAL, $interval ); } $h_raw = get_option( self::OPTION_NAME_SYNC_HORIZON, 120 ); $h = (int) $h_raw; if ( $h < 1 ) { $h = 120; } if ( $h > 365 ) { $h = 365; } if ( (string) $h_raw !== (string) $h ) { update_option( self::OPTION_NAME_SYNC_HORIZON, $h ); } $tz_raw = get_option( self::OPTION_NAME_TIMEZONE, '' ); $tz = trim( (string) $tz_raw ); if ( '' !== $tz ) { try { new DateTimeZone( $tz ); } catch ( Exception $e ) { $tz = ''; } } if ( (string) $tz_raw !== (string) $tz ) { update_option( self::OPTION_NAME_TIMEZONE, $tz ); } $progress_raw = get_option( self::OPTION_NAME_PROGRESS_IMAGES_ENABLED, false ); $progress = $progress_raw ? 1 : 0; if ( (string) $progress_raw !== (string) $progress ) { update_option( self::OPTION_NAME_PROGRESS_IMAGES_ENABLED, $progress ); } $experimental_raw = get_option( self::OPTION_NAME_EXPERIMENTAL_FEATURES_ENABLED, false ); $experimental = $experimental_raw ? 1 : 0; if ( (string) $experimental_raw !== (string) $experimental ) { update_option( self::OPTION_NAME_EXPERIMENTAL_FEATURES_ENABLED, $experimental ); } } public static function get_oauth_redirect_uri() { return admin_url( 'admin-post.php?action=tct_oauth_callback' ); } public function admin_menu() { add_options_page( 'Todoist Category Tracker', 'Todoist Category Tracker', 'manage_options', 'todoist-category-tracker', array( $this, 'render_settings_page' ) ); } public function register_settings() { register_setting( self::OPTION_GROUP, self::OPTION_NAME_CLIENT_ID, array( $this, 'sanitize_text' ) ); register_setting( self::OPTION_GROUP, self::OPTION_NAME_CLIENT_SECRET, array( $this, 'sanitize_text' ) ); register_setting( self::OPTION_GROUP, self::OPTION_NAME_SYNC_INTERVAL, array( $this, 'sanitize_interval' ) ); register_setting( self::OPTION_GROUP, self::OPTION_NAME_SYNC_HORIZON, array( $this, 'sanitize_horizon' ) ); register_setting( self::OPTION_GROUP, self::OPTION_NAME_TIMEZONE, array( $this, 'sanitize_timezone' ) ); register_setting( self::OPTION_GROUP, self::OPTION_NAME_END_OF_DAY_TIME, array( $this, 'sanitize_end_of_day_time' ) ); add_settings_section( 'tct_settings_section_main', 'Todoist OAuth Settings', '__return_false', 'todoist-category-tracker' ); add_settings_field( self::OPTION_NAME_CLIENT_ID, 'Todoist Client ID', array( $this, 'field_client_id' ), 'todoist-category-tracker', 'tct_settings_section_main' ); add_settings_field( self::OPTION_NAME_CLIENT_SECRET, 'Todoist Client Secret', array( $this, 'field_client_secret' ), 'todoist-category-tracker', 'tct_settings_section_main' ); add_settings_section( 'tct_settings_section_sync', 'Sync Settings', '__return_false', 'todoist-category-tracker' ); add_settings_field( self::OPTION_NAME_SYNC_INTERVAL, 'Background sync interval', array( $this, 'field_sync_interval' ), 'todoist-category-tracker', 'tct_settings_section_sync' ); add_settings_field( self::OPTION_NAME_SYNC_HORIZON, 'Sync horizon (days)', array( $this, 'field_sync_horizon' ), 'todoist-category-tracker', 'tct_settings_section_sync' ); add_settings_field( self::OPTION_NAME_TIMEZONE, 'Plugin Timezone', array( $this, 'field_timezone' ), 'todoist-category-tracker', 'tct_settings_section_sync' ); add_settings_field( self::OPTION_NAME_END_OF_DAY_TIME, 'End of day time', array( $this, 'field_end_of_day_time' ), 'todoist-category-tracker', 'tct_settings_section_sync' ); register_setting( self::OPTION_GROUP, self::OPTION_NAME_PROGRESS_IMAGES_ENABLED, array( $this, 'sanitize_checkbox' ) ); add_settings_section( 'tct_settings_section_progress_images', 'Progressive Reward Images', array( $this, 'section_progress_images_description' ), 'todoist-category-tracker' ); add_settings_field( self::OPTION_NAME_PROGRESS_IMAGES_ENABLED, 'Enable Feature', array( $this, 'field_progress_images_enabled' ), 'todoist-category-tracker', 'tct_settings_section_progress_images' ); add_settings_field( 'tct_generation_status', 'Generation Status', array( $this, 'field_generation_status' ), 'todoist-category-tracker', 'tct_settings_section_progress_images' ); register_setting( self::OPTION_GROUP, self::OPTION_NAME_EXPERIMENTAL_FEATURES_ENABLED, array( $this, 'sanitize_checkbox' ) ); add_settings_section( 'tct_settings_section_feature_flags', 'Feature Flags (Experimental)', array( $this, 'section_feature_flags_description' ), 'todoist-category-tracker' ); add_settings_field( self::OPTION_NAME_EXPERIMENTAL_FEATURES_ENABLED, 'Enable Experimental Features', array( $this, 'field_experimental_features_enabled' ), 'todoist-category-tracker', 'tct_settings_section_feature_flags' ); } public function sanitize_text( $v ) { return sanitize_text_field( $v ); } public function sanitize_interval( $v ) { $v = (int) $v; if ( ! in_array( $v, array( 5, 15, 30 ), true ) ) { $v = 15; } return $v; } public function sanitize_horizon( $v ) { $v = (int) $v; if ( $v < 1 ) { $v = 120; } if ( $v > 365 ) { $v = 365; } return $v; } public function sanitize_timezone( $v ) { $v = sanitize_text_field( $v ); $v = trim( $v ); if ( '' === $v ) { return ''; } try { new DateTimeZone( $v ); } catch ( Exception $e ) { return ''; } return $v; } public function sanitize_end_of_day_time( $v ) { $v = sanitize_text_field( (string) $v ); $v = trim( $v ); if ( '' === $v ) { return ''; } if ( 1 === preg_match( '/^(\d{1,2}):(\d{2})(?:\:(\d{2}))?$/', $v, $m ) ) { $h = (int) $m[1]; $min = (int) $m[2]; if ( $h >= 0 && $h <= 23 && $min >= 0 && $min <= 59 ) { return sprintf( '%02d:%02d', $h, $min ); } } add_settings_error( self::OPTION_NAME_END_OF_DAY_TIME, 'tct_invalid_end_of_day_time', 'End of day time must be in 24-hour HH:MM format (for example 23:00).', 'error' ); return self::get_end_of_day_time(); } public function sanitize_checkbox( $v ) { return $v ? 1 : 0; } public function field_client_id() { $val = esc_attr( self::get_client_id() ); echo '<input type="text" class="regular-text" name="' . esc_attr( self::OPTION_NAME_CLIENT_ID ) . '" value="' . $val . '" />'; echo '<p class="description">Create a Todoist app in the Todoist App Management Console and paste the Client ID here.</p>'; } public function field_client_secret() { $val = esc_attr( self::get_client_secret() ); echo '<input type="password" class="regular-text" name="' . esc_attr( self::OPTION_NAME_CLIENT_SECRET ) . '" value="' . $val . '" autocomplete="new-password" />'; echo '<p class="description">Paste the Todoist Client Secret here.</p>'; } public function field_sync_interval() { $val = (int) self::get_sync_interval_minutes(); echo '<select name="' . esc_attr( self::OPTION_NAME_SYNC_INTERVAL ) . '">'; foreach ( array( 5, 15, 30 ) as $opt ) { echo '<option value="' . esc_attr( $opt ) . '" ' . selected( $val, $opt, false ) . '>' . esc_html( $opt ) . ' minutes</option>'; } echo '</select>'; echo '<p class="description">Uses WP-Cron (runs on traffic). Manual sync is also available in the shortcode dashboard.</p>'; } public function field_sync_horizon() { $val = (int) self::get_sync_horizon_days(); echo '<input type="number" min="1" max="365" name="' . esc_attr( self::OPTION_NAME_SYNC_HORIZON ) . '" value="' . esc_attr( $val ) . '" />'; echo '<p class="description">How many days back to refresh from Todoist on each sync (default: 120). Keeping this smaller makes sync faster.</p>'; } public function field_timezone() { $current = self::get_timezone(); echo '<select name="' . esc_attr( self::OPTION_NAME_TIMEZONE ) . '" style="min-width:300px;">'; $wp_tz = get_option( 'timezone_string', '' ); if ( ! $wp_tz ) { $offset = (float) get_option( 'gmt_offset', 0 ); $sign = ( $offset >= 0 ) ? '+' : '-'; $h = abs( (int) $offset ); $m = abs( (int) round( ( $offset - (int) $offset ) * 60 ) ); $wp_tz = sprintf( 'UTC%s%d:%02d', $sign, $h, $m ); } $sel = ( '' === $current ) ? ' selected="selected"' : ''; echo '<option value=""' . $sel . '>-- Use WordPress site timezone (' . esc_html( $wp_tz ) . ') --</option>'; if ( function_exists( 'wp_timezone_choice' ) ) { $choice_val = $current ? $current : '___none___'; echo wp_timezone_choice( $choice_val, get_user_locale() ); } else { $zones = timezone_identifiers_list(); foreach ( $zones as $zone ) { $sel_attr = ( $current === $zone ) ? ' selected="selected"' : ''; echo '<option value="' . esc_attr( $zone ) . '"' . $sel_attr . '>' . esc_html( str_replace( '_', ' ', $zone ) ) . '</option>'; } } echo '</select>'; echo '<p class="description">Override the timezone used for goal interval boundaries (day/week/month rollovers).</p>'; echo '<p class="description" style="color:#dba617;"><strong>Note:</strong> Active goal intervals will immediately recalculate using the new timezone. Past completion timestamps are not modified.</p>'; } public function field_end_of_day_time() { $current = self::get_end_of_day_time(); $val = esc_attr( $current ); echo '<input type="time" name="' . esc_attr( self::OPTION_NAME_END_OF_DAY_TIME ) . '" value="' . $val . '" step="60" pattern="[0-2][0-9]:[0-5][0-9]" placeholder="23:00" />'; echo '<p class="description">Format: <code>HH:MM</code> (24-hour), for example <code>23:00</code>. Leave blank to disable.</p>'; $tz = self::get_timezone(); $wp_tz = get_option( 'timezone_string', '' ); if ( ! $wp_tz ) { $offset = (float) get_option( 'gmt_offset', 0 ); $sign = ( $offset >= 0 ) ? '+' : '-'; $h = abs( (int) $offset ); $m = abs( (int) round( ( $offset - (int) $offset ) * 60 ) ); $wp_tz = sprintf( 'UTC%s%d:%02d', $sign, $h, $m ); } $effective = ( '' !== $tz ) ? $tz : $wp_tz; $label = ( '' !== $tz ) ? 'plugin timezone override' : 'WordPress site timezone'; echo '<p class="description">Interpreted in ' . esc_html( $label ) . ': <code>' . esc_html( $effective ) . '</code>.</p>'; echo '<p class="description">This will be used by the end-of-day auto-miss job for eligible 1/day positive goals.</p>'; } public function section_progress_images_description() { echo '<p>Generate progressive reward image variants that reveal from grayscale to full color as you progress toward your reward. '; echo 'Images are generated locally using PHP\'s <strong>GD</strong> extension (no external API key required).</p>'; echo '<p class="description" style="margin-top:6px;">Generation runs in the background via WP-Cron when you upload/change your reward image.</p>'; } public function field_progress_images_enabled() { $const_override = defined( 'TCT_FEATURE_REWARD_PROGRESS_IMAGES' ); $enabled = self::is_progress_images_enabled(); $disabled_attr = $const_override ? ' disabled' : ''; $checked_attr = $enabled ? ' checked' : ''; echo '<label>'; echo '<input type="checkbox" name="' . esc_attr( self::OPTION_NAME_PROGRESS_IMAGES_ENABLED ) . '" value="1"' . $checked_attr . $disabled_attr . ' />'; echo ' Enable progressive reward image generation'; echo '</label>'; if ( $const_override ) { $status = $enabled ? 'enabled' : 'disabled'; echo '<p class="description" style="color: #dba617;">&#x26A0; This setting is overridden by <code>TCT_FEATURE_REWARD_PROGRESS_IMAGES</code> constant in wp-config.php (currently ' . $status . ').</p>'; } else { echo '<p class="description">When enabled and you upload a reward image, 40 variants will be generated in the background.</p>'; } } public function field_generation_status() { $feature_enabled = self::is_progress_images_enabled(); if ( ! $feature_enabled ) { echo '<p class="description" style="color: #666;">Feature is disabled. Enable it above to see generation status.</p>'; return; } if ( ! class_exists( 'TCT_Reward' ) || ! is_callable( array( 'TCT_Reward', 'find_users_with_active_jobs' ) ) ) { echo '<p class="description" style="color: #d63638;">TCT_Reward class not available.</p>'; return; } if ( class_exists( 'TCT_Reward_Progress_Generator' ) && is_callable( array( 'TCT_Reward_Progress_Generator', 'check_programmatic_prereqs' ) ) ) { $pre = TCT_Reward_Progress_Generator::check_programmatic_prereqs(); if ( empty( $pre['ok'] ) ) { $msg = isset( $pre['error'] ) ? (string) $pre['error'] : 'Reward progress image generator prerequisites are not met.'; echo '<p class="description" style="color: #dba617;">&#x26A0; ' . esc_html( $msg ) . '</p>'; } else { echo '<p class="description" style="color: #00a32a;">&#x2713; GD is available and the uploads directory is writable.</p>'; } } else { echo '<p class="description" style="color: #dba617;">&#x26A0; Reward progress generator not available.</p>'; } $cron_scheduled = false; if ( class_exists( 'TCT_Reward' ) ) { $hook = TCT_Reward::CRON_HOOK_PROGRESS_GENERATION; $next_run = wp_next_scheduled( $hook ); $cron_scheduled = ( false !== $next_run ); } $active_users = TCT_Reward::find_users_with_active_jobs( 50 ); if ( empty( $active_users ) ) { echo '<p style="color: #00a32a;">&#x2713; No active generation jobs.</p>'; if ( $cron_scheduled ) { echo '<p class="description">Cron is scheduled and will process new jobs when queued.</p>'; } return; } echo '<table class="widefat striped" style="max-width: 600px;">'; echo '<thead><tr><th>User</th><th>Progress</th><th>Status</th></tr></thead>'; echo '<tbody>'; foreach ( $active_users as $user_id ) { $user_id = (int) $user_id; $user = get_userdata( $user_id ); $username = $user ? $user->user_login : 'User #' . $user_id; $progress = TCT_Reward::get_generation_job_progress( $user_id ); $status = isset( $progress['status'] ) ? $progress['status'] : 'unknown'; $current = isset( $progress['current'] ) ? (int) $progress['current'] : 0; $total = isset( $progress['total'] ) ? (int) $progress['total'] : 40; $message = isset( $progress['message'] ) ? $progress['message'] : ''; $error_type = isset( $progress['error_type'] ) ? $progress['error_type'] : ''; $retry_count = isset( $progress['retry_count'] ) ? (int) $progress['retry_count'] : 0; $pct = ( $total > 0 ) ? round( ( $current / $total ) * 100 ) : 0; $status_icon = ''; $status_color = '#50575e'; switch ( $status ) { case 'pending': $status_icon = '&#x23F3;'; $status_color = '#dba617'; break; case 'running': $status_icon = '&#x1F504;'; $status_color = '#2271b1'; break; case 'complete': $status_icon = '&#x2713;'; $status_color = '#00a32a'; break; case 'error': $status_icon = '&#x2717;'; $status_color = '#d63638'; break; } echo '<tr>'; echo '<td>' . esc_html( $username ) . '</td>'; echo '<td>'; echo '<div style="display: flex; align-items: center; gap: 8px;">'; echo '<div style="width: 100px; height: 8px; background: #dcdcde; border-radius: 4px; overflow: hidden;">'; echo '<div style="width: ' . esc_attr( $pct ) . '%; height: 100%; background: ' . esc_attr( $status_color ) . ';"></div>'; echo '</div>'; echo '<span>' . esc_html( $current ) . '/' . esc_html( $total ) . '</span>'; echo '</div>'; echo '</td>'; echo '<td style="color: ' . esc_attr( $status_color ) . ';">'; echo $status_icon . ' ' . esc_html( ucfirst( $status ) ); if ( 'running' === $status && $retry_count > 0 ) { echo '<br><small style="color: #dba617;">Retry ' . esc_html( $retry_count ) . '/' . esc_html( TCT_Reward::JOB_MAX_RETRIES ) . '</small>'; } if ( 'error' === $status ) { if ( $error_type ) { $type_labels = array( 'rate_limit' => 'Rate Limit', 'auth' => 'Auth Error', 'invalid_input' => 'Invalid Input', 'server' => 'Server Error', 'network' => 'Network Error', 'filesystem' => 'File Error', ); $type_label = isset( $type_labels[ $error_type ] ) ? $type_labels[ $error_type ] : ucfirst( $error_type ); echo '<br><small style="color: #666;">[' . esc_html( $type_label ) . ']</small>'; } if ( ! empty( $message ) ) { $display_msg = strlen( $message ) > 100 ? substr( $message, 0, 100 ) . '...' : $message; echo '<br><small style="color: #d63638;" title="' . esc_attr( $message ) . '">' . esc_html( $display_msg ) . '</small>'; } } echo '</td>'; echo '</tr>'; } echo '</tbody></table>'; if ( $cron_scheduled ) { $next_run = wp_next_scheduled( TCT_Reward::CRON_HOOK_PROGRESS_GENERATION ); $next_in = $next_run - time(); if ( $next_in > 0 ) { echo '<p class="description" style="margin-top: 8px;">Next cron run in ' . esc_html( $next_in ) . ' seconds.</p>'; } else { echo '<p class="description" style="margin-top: 8px;">Cron is due to run.</p>'; } } else { echo '<p class="description" style="margin-top: 8px; color: #dba617;">&#x26A0; Cron is not scheduled. Jobs may not process automatically.</p>'; } } public function section_feature_flags_description() { echo '<p>Feature flags allow gradual rollout of in-development features. '; echo '<strong>Keep this OFF</strong> unless you are explicitly testing a new feature.</p>'; echo '<p class="description">You can also force enable/disable via the <code>TCT_FEATURE_EXPERIMENTAL</code> constant in <code>wp-config.php</code>.</p>'; } public function field_experimental_features_enabled() { $const_override = defined( 'TCT_FEATURE_EXPERIMENTAL' ); $enabled = self::is_experimental_features_enabled(); $disabled_attr = $const_override ? ' disabled' : ''; $checked_attr = $enabled ? ' checked' : ''; echo '<label>'; echo '<input type="checkbox" name="' . esc_attr( self::OPTION_NAME_EXPERIMENTAL_FEATURES_ENABLED ) . '" value="1"' . $checked_attr . $disabled_attr . ' />'; echo ' Enable experimental features (for testing only)'; echo '</label>'; if ( $const_override ) { $status = $enabled ? 'enabled' : 'disabled'; echo '<p class="description" style="color: #dba617;">&#x26A0; This setting is overridden by <code>TCT_FEATURE_EXPERIMENTAL</code> in <code>wp-config.php</code> (currently ' . esc_html( $status ) . ').</p>'; } } public function render_settings_page() { if ( ! current_user_can( 'manage_options' ) ) { return; } $redirect_uri = esc_html( self::get_oauth_redirect_uri() ); ?>
        <div class="wrap">
